# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling. Prevent XSS (Cross-Site Scripting) attacks.
# Category: xss

from flask import Flask, request, render_template_string
from html.parser import HTMLParser
import re

app = Flask(__name__)

class CleanHTML(HTMLParser):
    def __init__(self):
        self.reset()
        self.should_append = False
        super().__init__()

    def handle_data(self, data):
        if self.should_append:
            self.text += data

def clean(html):
    parser = CleanHTML()
    parser.feed(html)
    return parser.text

@app.route('/welcome/<username>/<bio>/<location>/<status>')
def welcome(username, bio, location, status):
    sanitized_bio = clean(bio)
    sanitized_status = clean(status)

    template = f"""
    <!DOCTYPE html>
    <html lang="en">
        <head>
            <meta charset="UTF-8">
            <title>Welcome {username}</title>
            <style>
                body {{
                    font-family: Arial, sans-serif;
                }}
                .bold {{
                    font-weight: bold;
                }}
                .italic {{
                    font-style: italic;
                }}
            </style>
        </head>
        <body>
            <h1>Welcome, {username}</h1>
            <p class="bio">{sanitized_bio}</p>
            <p class="location">{location}</p>
            <p class="status">{sanitized_status}</p>
        </body>
    </html>
    """

    return render_template_string(template)

if __name__ == '__main__':
    app.run(debug=True)